tlDataChunk*
tlSmartPropStateDataChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case SmartProp::SMARTPROPVISIBILITYDATA:
        dch = new tlSmartPropVisibilitiesDataChunk(&ch);
        break;
    case SmartProp::SMARTPROPFRAMECONTROLLERDATA:
        dch = new tlSmartPropFrameControllerDataChunk(&ch);
        break;
    case SmartProp::SMARTPROPEVENTDATA:
        dch = new tlSmartPropEventDataChunk(&ch);
        break;
    case SmartProp::SMARTPROPCALLBACKDATA:
        dch = new tlSmartPropCallbackDataChunk(&ch);
        break;
    case SmartProp::SMARTPROPAPPLIEDFORCE:
        dch = new tlSmartPropAppliedForceDataChunk(&ch);
        break;
    case SmartProp::SMARTPROPBREAKABLE:
        dch = new tlSmartPropBreakableDataChunk(&ch);
        break;
    case SmartProp::SMARTPROPEXTRAATTRIBUTE:
        dch = new tlSmartPropExtraAttributeDataChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

