tlSmartPropVisibilitiesDataChunk::~tlSmartPropVisibilitiesDataChunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlSmartPropVisibilitiesDataChunk::tlSmartPropVisibilitiesDataChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == SmartProp::SMARTPROPVISIBILITYDATA);
    ident = SmartProp::SMARTPROPVISIBILITYDATA;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    visible = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(SmartProp::SMARTPROPVISIBILITYDATA);
    }
}

void
tlSmartPropVisibilitiesDataChunk::Init()
{
    ident = SmartProp::SMARTPROPVISIBILITYDATA;
    name = NULL;
    visible = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(SmartProp::SMARTPROPVISIBILITYDATA);
    }
}

long 
tlSmartPropVisibilitiesDataChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( visible );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlSmartPropVisibilitiesDataChunk&
tlSmartPropVisibilitiesDataChunk::operator=(const tlSmartPropVisibilitiesDataChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    visible = a.visible;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlSmartPropVisibilitiesDataChunk::operator==(const tlDataChunk& a)
{

    const tlSmartPropVisibilitiesDataChunk* aptr = dynamic_cast<const tlSmartPropVisibilitiesDataChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(visible == aptr->visible))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlSmartPropVisibilitiesDataChunk::NameCompare(const tlDataChunk& a)
{

    const tlSmartPropVisibilitiesDataChunk* aptr = dynamic_cast<const tlSmartPropVisibilitiesDataChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


