tlSmartPropVisibilitiesDataChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlSmartPropVisibilitiesDataChunk(ch);
    return dtCh;
}

void
tlSmartPropVisibilitiesDataChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutLong(visible);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlSmartPropVisibilitiesDataChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlSmartPropVisibilitiesDataChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name    = \"%s\"\n",indent,"",name);
    printf("%*s  Visible = %ld\n",indent,"",visible);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlSmartPropVisibilitiesDataChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name   \n",indent,"",name);
    printf("%*s  int   %12ld # Visible\n",indent,"",visible);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

