tlSmartPropBreakableDataChunk::tlSmartPropBreakableDataChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == SmartProp::SMARTPROPBREAKABLE);
    ident = SmartProp::SMARTPROPBREAKABLE;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    isbreakable = f->GetLong();
    joint = f->GetLong();
    onframe = f->GetFloat();
    forcex = f->GetFloat();
    forcey = f->GetFloat();
    forcez = f->GetFloat();
    posx = f->GetFloat();
    posy = f->GetFloat();
    posz = f->GetFloat();
    f->GetPString(buf);
    material = strnew(buf);
    materialenum = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(SmartProp::SMARTPROPBREAKABLE);
    }
}

