bool
tlSmartPropBreakableDataChunk::operator==(const tlDataChunk& a)
{

    const tlSmartPropBreakableDataChunk* aptr = dynamic_cast<const tlSmartPropBreakableDataChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(isbreakable == aptr->isbreakable))
    {
        return false;
    }
    if(!(joint == aptr->joint))
    {
        return false;
    }
    if(!(onframe == aptr->onframe))
    {
        return false;
    }
    if(!(forcex == aptr->forcex))
    {
        return false;
    }
    if(!(forcey == aptr->forcey))
    {
        return false;
    }
    if(!(forcez == aptr->forcez))
    {
        return false;
    }
    if(!(posx == aptr->posx))
    {
        return false;
    }
    if(!(posy == aptr->posy))
    {
        return false;
    }
    if(!(posz == aptr->posz))
    {
        return false;
    }
    if(strcmp(material, aptr->material) != 0)
    {
        return false;
    }
    if(!(materialenum == aptr->materialenum))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

