// tlSmartPropExtraAttributeDataChunk

int tlSmartPropExtraAttributeDataChunk::sortPriority = -1;

tlSmartPropExtraAttributeDataChunk::tlSmartPropExtraAttributeDataChunk()
{
    Init();
}

tlSmartPropExtraAttributeDataChunk::tlSmartPropExtraAttributeDataChunk(const tlSmartPropExtraAttributeDataChunk& ch)
{
    Init();
    *this = ch;
}

tlSmartPropExtraAttributeDataChunk::~tlSmartPropExtraAttributeDataChunk()
{

    if(extraattribute != NULL){
        strdelete(extraattribute);
    }
}

tlSmartPropExtraAttributeDataChunk::tlSmartPropExtraAttributeDataChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == SmartProp::SMARTPROPEXTRAATTRIBUTE);
    ident = SmartProp::SMARTPROPEXTRAATTRIBUTE;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    extraattribute = strnew(buf);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(SmartProp::SMARTPROPEXTRAATTRIBUTE);
    }
}

void
tlSmartPropExtraAttributeDataChunk::Init()
{
    ident = SmartProp::SMARTPROPEXTRAATTRIBUTE;
    extraattribute = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(SmartProp::SMARTPROPEXTRAATTRIBUTE);
    }
}

long 
tlSmartPropExtraAttributeDataChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( extraattribute );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlSmartPropExtraAttributeDataChunk&
tlSmartPropExtraAttributeDataChunk::operator=(const tlSmartPropExtraAttributeDataChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    extraattribute = strnew(a.extraattribute);

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlSmartPropExtraAttributeDataChunk::operator==(const tlDataChunk& a)
{

    const tlSmartPropExtraAttributeDataChunk* aptr = dynamic_cast<const tlSmartPropExtraAttributeDataChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(extraattribute, aptr->extraattribute) != 0)
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlSmartPropExtraAttributeDataChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


tlDataChunk*
tlSmartPropExtraAttributeDataChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlSmartPropExtraAttributeDataChunk(ch);
    return dtCh;
}

void
tlSmartPropExtraAttributeDataChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(extraattribute);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlSmartPropExtraAttributeDataChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlSmartPropExtraAttributeDataChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  ExtraAttribute = \"%s\"\n",indent,"",extraattribute);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlSmartPropExtraAttributeDataChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # ExtraAttribute\n",indent,"",extraattribute);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

